CREATE OR REPLACE FUNCTION public.admin_delete_user(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    deleted_user jsonb;
    is_admin boolean;
BEGIN
    -- Security: Only admins can call this
    SELECT role = 'admin' INTO is_admin
    FROM profiles WHERE id = auth.uid();
    
    IF NOT is_admin THEN
        RAISE EXCEPTION 'Unauthorized: Admin role required';
    END IF;
    
    -- Prevent self-deletion
    IF p_user_id = auth.uid() THEN
        RAISE EXCEPTION 'Cannot delete your own account';
    END IF;
    
    -- Get user info before deletion (for confirmation/logging)
    SELECT jsonb_build_object(
        'id', id,
        'username', username,
        'role', role,
        'created_at', created_at,
        'deleted_at', now()
    ) INTO deleted_user
    FROM profiles WHERE id = p_user_id;
    
    -- Check if user exists
    IF deleted_user IS NULL THEN
        RAISE EXCEPTION 'User not found';
    END IF;
    
    -- Delete from profiles table
    -- Foreign key CASCADE will handle:
    --   - playlists (user_id FK)
    --   - playlist_items (via playlists cascade)
    --   - watch_party (created_by FK)  
    --   - watch_party_members (user_id FK)
    --   - playlist_likes (user_id FK)
    --   - follows (follower_id/following_id FK)
    DELETE FROM profiles WHERE id = p_user_id;
    
    -- Return deleted user info for audit logging
    RETURN deleted_user;
END;
$function$

CREATE OR REPLACE FUNCTION public.clear_my_watch_history()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  is_enabled text;
begin
  select value into is_enabled 
  from public.app_settings 
  where key = 'clear_history_enabled';
  
  if is_enabled != 'true' then
    raise exception 'This feature is currently disabled by the administrator.';
  end if;

  update public.profiles
  set watch_history = '{}'::jsonb
  where id = auth.uid();
end;
$function$

CREATE OR REPLACE FUNCTION public.prune_watch_history()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  user_record RECORD;
  new_history JSONB;
  cutoff_ms BIGINT;
BEGIN
  -- 60 days ago in milliseconds
  cutoff_ms := (EXTRACT(EPOCH FROM NOW()) - (60 * 24 * 60 * 60)) * 1000;

  FOR user_record IN SELECT id, watch_history FROM public.profiles WHERE watch_history IS NOT NULL LOOP
    
    -- Filter items older than 60 days
    SELECT jsonb_object_agg(key, value)
    INTO new_history
    FROM jsonb_each(user_record.watch_history)
    WHERE (value->>'lastUpdated')::bigint >= cutoff_ms;

    -- Update if changed
    IF new_history IS DISTINCT FROM user_record.watch_history THEN
      UPDATE public.profiles
      SET watch_history = COALESCE(new_history, '{}'::jsonb)
      WHERE id = user_record.id;
    END IF;
    
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.track_playlist_view(p_playlist_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  current_analytics jsonb;
  current_week text;
  current_month text;
  stored_week text;
  stored_month text;
  new_analytics jsonb;
begin
  current_analytics := (select analytics from public.playlists where id = p_playlist_id);
  current_week := to_char(now(), 'IYYY-IW'); -- ISO week format
  current_month := to_char(now(), 'YYYY-MM');
  
  stored_week := current_analytics->>'week_start';
  stored_month := current_analytics->>'month_start';
  
  -- Build new analytics object
  new_analytics := jsonb_build_object(
    'total_views', coalesce((current_analytics->>'total_views')::int, 0) + 1,
    'weekly_views', case when stored_week = current_week then coalesce((current_analytics->>'weekly_views')::int, 0) + 1 else 1 end,
    'monthly_views', case when stored_month = current_month then coalesce((current_analytics->>'monthly_views')::int, 0) + 1 else 1 end,
    'week_start', current_week,
    'month_start', current_month,
    'last_viewers', (
      select jsonb_agg(viewer order by (viewer->>'timestamp')::bigint desc)
      from (
        select jsonb_array_elements(coalesce(current_analytics->'last_viewers', '[]'::jsonb)) as viewer
        union all
        select jsonb_build_object('user_id', auth.uid()::text, 'timestamp', extract(epoch from now())::bigint)
        limit 10
      ) viewers
    )
  );
  
  update public.playlists
  set analytics = new_analytics
  where id = p_playlist_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.update_watch_history(p_user_id uuid, p_tmdb_id text, p_data jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  current_stats JSONB;
  current_history JSONB;
  is_new_item BOOLEAN;
  media_type TEXT;
  previous_last_watched TIMESTAMPTZ;
  days_since_last_watch INT;
  current_streak INT;
  genres JSONB;
  genre_name TEXT;
  current_month TEXT;
  current_year INT;
  stored_year INT;
  title TEXT;
  title_rewatch_count INT;
  today TEXT;
  today_count INT;
BEGIN
  SELECT watch_history, stats INTO current_history, current_stats 
  FROM public.profiles WHERE id = p_user_id;

  -- Initialize if null
  IF current_stats IS NULL THEN 
    current_stats := jsonb_build_object(
      'total_movies', 0,
      'total_shows', 0,
      'streak_days', 0,
      'max_streak', 0,
      'genre_counts', '{}'::jsonb,
      'monthly_watches', '{}'::jsonb,
      'first_watch_of_year', null,
      'year', extract(year from now()),
      'rewatch_count', 0,
      'binge_days', 0,
      'daily_watch_count', '{}'::jsonb,
      'title_rewatch_counts', '{}'::jsonb,
      'past_years', '{}'::jsonb
    );
  END IF;
  
  IF current_history IS NULL THEN 
    current_history := '{}'::jsonb; 
  END IF;

  -- ===============================================
  -- YEAR TRANSITION LOGIC (Jan 1st Auto-Reset)
  -- ===============================================
  current_year := extract(year from now());
  stored_year := COALESCE((current_stats->>'year')::int, current_year);

  IF stored_year < current_year THEN
     -- Initialize past_years if needed
     IF current_stats->'past_years' IS NULL THEN
        current_stats := jsonb_set(current_stats, '{past_years}', '{}'::jsonb);
     END IF;
     
     -- Snapshot old year's stats (e.g., save 2026 stats before resetting)
     current_stats := jsonb_set(
        current_stats,
        array['past_years', stored_year::text],
        current_stats - 'past_years'
     );

     -- Reset all counters for new year
     current_stats := jsonb_set(current_stats, '{total_movies}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{total_shows}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{streak_days}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{max_streak}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{genre_counts}', '{}'::jsonb);
     current_stats := jsonb_set(current_stats, '{monthly_watches}', '{}'::jsonb);
     current_stats := jsonb_set(current_stats, '{first_watch_of_year}', 'null'::jsonb);
     current_stats := jsonb_set(current_stats, '{rewatch_count}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{binge_days}', '0'::jsonb);
     current_stats := jsonb_set(current_stats, '{daily_watch_count}', '{}'::jsonb);
     current_stats := jsonb_set(current_stats, '{title_rewatch_counts}', '{}'::jsonb);
     current_stats := jsonb_set(current_stats, '{year}', current_year::text::jsonb);
  END IF;

  -- Ensure fields exist (for users running migration mid-year)
  IF current_stats->'genre_counts' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{genre_counts}', '{}'::jsonb);
  END IF;
  IF current_stats->'max_streak' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{max_streak}', '0'::jsonb);
  END IF;
  IF current_stats->'monthly_watches' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{monthly_watches}', '{}'::jsonb);
  END IF;
  IF current_stats->'year' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{year}', to_jsonb(extract(year from now())::int));
  END IF;
  IF current_stats->'rewatch_count' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{rewatch_count}', '0'::jsonb);
  END IF;
  IF current_stats->'binge_days' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{binge_days}', '0'::jsonb);
  END IF;
  IF current_stats->'daily_watch_count' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{daily_watch_count}', '{}'::jsonb);
  END IF;
  IF current_stats->'title_rewatch_counts' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{title_rewatch_counts}', '{}'::jsonb);
  END IF;
  IF current_stats->'past_years' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{past_years}', '{}'::jsonb);
  END IF;

  -- Extract metadata
  media_type := p_data->>'type';
  genres := p_data->'genres';
  is_new_item := NOT (current_history ? p_tmdb_id);

  -- ===============================================
  -- REWATCH TRACKING
  -- ===============================================
  IF NOT is_new_item THEN
    current_stats := jsonb_set(
      current_stats,
      '{rewatch_count}',
      (COALESCE((current_stats->>'rewatch_count')::int, 0) + 1)::text::jsonb
    );
    
    title := p_data->>'title';
    IF title IS NOT NULL THEN
      title_rewatch_count := COALESCE((current_stats->'title_rewatch_counts'->>title)::int, 0) + 1;
      current_stats := jsonb_set(
        current_stats,
        array['title_rewatch_counts', title],
        title_rewatch_count::text::jsonb
      );
    END IF;
  END IF;

  -- Update watch history
  current_history := jsonb_set(current_history, array[p_tmdb_id], p_data);

  -- Update counters if new item
  IF is_new_item THEN
    IF media_type = 'movie' THEN
      current_stats := jsonb_set(current_stats, '{total_movies}', 
        ((current_stats->>'total_movies')::int + 1)::text::jsonb);
    ELSIF media_type = 'tv' THEN
      current_stats := jsonb_set(current_stats, '{total_shows}', 
        ((current_stats->>'total_shows')::int + 1)::text::jsonb);
    END IF;

    IF genres IS NOT NULL AND jsonb_typeof(genres) = 'array' THEN
      FOR genre_name IN SELECT jsonb_array_elements_text(genres)
      LOOP
        current_stats := jsonb_set(
          current_stats,
          array['genre_counts', genre_name],
          (COALESCE((current_stats->'genre_counts'->>genre_name)::int, 0) + 1)::text::jsonb
        );
      END LOOP;
    END IF;
  END IF;

  -- Calculate streak
  previous_last_watched := (current_stats->>'last_watched')::timestamptz;
  current_streak := COALESCE((current_stats->>'streak_days')::int, 0);
  
  IF previous_last_watched IS NULL THEN
    current_streak := 1;
  ELSE
    days_since_last_watch := CURRENT_DATE - DATE(previous_last_watched);
    
    IF days_since_last_watch = 0 THEN
      current_streak := current_streak;
    ELSIF days_since_last_watch = 1 THEN
      current_streak := current_streak + 1;
    ELSE
      current_streak := 1;
    END IF;
  END IF;
  
  current_stats := jsonb_set(current_stats, '{streak_days}', current_streak::text::jsonb);
  current_stats := jsonb_set(current_stats, '{last_watched}', to_jsonb(now()));

  IF current_streak > COALESCE((current_stats->>'max_streak')::int, 0) THEN
    current_stats := jsonb_set(current_stats, '{max_streak}', current_streak::text::jsonb);
  END IF;

  -- Track monthly watches
  current_month := to_char(now(), 'YYYY-MM');
  current_stats := jsonb_set(
    current_stats, 
    array['monthly_watches', current_month], 
    (COALESCE((current_stats->'monthly_watches'->>current_month)::int, 0) + 1)::text::jsonb
  );

  -- ===============================================
  -- BINGE DAY TRACKING
  -- ===============================================
  today := to_char(now(), 'YYYY-MM-DD');
  today_count := COALESCE((current_stats->'daily_watch_count'->>today)::int, 0) + 1;
  
  current_stats := jsonb_set(
    current_stats,
    array['daily_watch_count', today],
    today_count::text::jsonb
  );
  
  IF today_count = 3 THEN
    current_stats := jsonb_set(
      current_stats,
      '{binge_days}',
      (COALESCE((current_stats->>'binge_days')::int, 0) + 1)::text::jsonb
    );
  END IF;
  
  -- Cleanup old daily counts (keep last 30 days)
  current_stats := jsonb_set(
    current_stats,
    '{daily_watch_count}',
    (
      SELECT COALESCE(jsonb_object_agg(key, value), '{}'::jsonb)
      FROM jsonb_each(current_stats->'daily_watch_count')
      WHERE to_date(key, 'YYYY-MM-DD') > CURRENT_DATE - INTERVAL '30 days'
    )
  );

  -- Track first watch of year
  current_year := extract(year from now());
  IF current_stats->'first_watch_of_year' IS NULL OR
     COALESCE((current_stats->'first_watch_of_year'->>'year')::int, 0) < current_year THEN
    current_stats := jsonb_set(current_stats, '{first_watch_of_year}', jsonb_build_object(
      'tmdb_id', p_tmdb_id,
      'title', p_data->>'title',
      'date', current_date::text,
      'type', media_type,
      'year', current_year
    ));
  END IF;

  -- Save
  UPDATE public.profiles
  SET 
    watch_history = current_history,
    stats = current_stats,
    last_seen_activity = now()
  WHERE id = p_user_id;

END;
$function$

CREATE OR REPLACE FUNCTION public.update_watch_history_v2(p_user_id uuid, p_tmdb_id text, p_data jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  current_stats JSONB;
  current_history JSONB;
  is_new_item BOOLEAN;
  media_type TEXT;
  previous_last_watched TIMESTAMPTZ;
  days_since_last_watch INT;
  current_streak INT;
  genres JSONB;
  genre_name TEXT;
BEGIN
  SELECT watch_history, stats INTO current_history, current_stats 
  FROM public.profiles WHERE id = p_user_id;

  IF current_history IS NULL THEN current_history := '{}'::jsonb; END IF;
  IF current_stats IS NULL THEN 
    current_stats := '{"total_movies": 0, "total_shows": 0, "streak_days": 0, "genre_counts": {}}'::jsonb; 
  END IF;
  IF current_stats->'genre_counts' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{genre_counts}', '{}'::jsonb);
  END IF;

  media_type := p_data->>'type';
  genres := p_data->'genres';
  is_new_item := NOT (current_history ? p_tmdb_id);
  current_history := jsonb_set(current_history, array[p_tmdb_id], p_data);

  IF is_new_item THEN
    IF media_type = 'movie' THEN
      current_stats := jsonb_set(current_stats, '{total_movies}', 
        ((current_stats->>'total_movies')::int + 1)::text::jsonb);
    ELSIF media_type = 'tv' THEN
      current_stats := jsonb_set(current_stats, '{total_shows}', 
        ((current_stats->>'total_shows')::int + 1)::text::jsonb);
    END IF;

    IF genres IS NOT NULL AND jsonb_typeof(genres) = 'array' THEN
      FOR genre_name IN SELECT jsonb_array_elements_text(genres)
      LOOP
        current_stats := jsonb_set(
          current_stats,
          array['genre_counts', genre_name],
          (COALESCE((current_stats->'genre_counts'->>genre_name)::int, 0) + 1)::text::jsonb
        );
      END LOOP;
    END IF;
  END IF;

  previous_last_watched := (current_stats->>'last_watched')::timestamptz;
  current_streak := COALESCE((current_stats->>'streak_days')::int, 0);
  
  IF previous_last_watched IS NULL THEN
    current_streak := 1;
  ELSE
    days_since_last_watch := EXTRACT(DAY FROM (CURRENT_DATE - DATE(previous_last_watched)));
    IF days_since_last_watch = 0 THEN current_streak := current_streak;
    ELSIF days_since_last_watch = 1 THEN current_streak := current_streak + 1;
    ELSE current_streak := 1;
    END IF;
  END IF;
  
  current_stats := jsonb_set(current_stats, '{streak_days}', current_streak::text::jsonb);
  current_stats := jsonb_set(current_stats, '{last_watched}', to_jsonb(now()));

  UPDATE public.profiles
  SET watch_history = current_history, stats = current_stats, last_seen_activity = now()
  WHERE id = p_user_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_watch_history_with_stats(p_user_id uuid, p_tmdb_id text, p_media_type text, p_duration integer, p_genres text[], p_data jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  current_stats JSONB;
  current_history JSONB;
  is_new_item BOOLEAN;
  g text;
BEGIN
  -- Fetch current data
  SELECT watch_history, stats INTO current_history, current_stats 
  FROM public.profiles WHERE id = p_user_id;

  -- Initialize defaults
  IF current_history IS NULL THEN current_history := '{}'::jsonb; END IF;
  IF current_stats IS NULL THEN 
    current_stats := '{"total_movies": 0, "total_shows": 0, "streak_days": 0, "genre_counts": {}}'::jsonb; 
  END IF;

  -- Check if new item
  is_new_item := NOT (current_history ? p_tmdb_id);

  -- Update watch history
  current_history := jsonb_set(current_history, array[p_tmdb_id], p_data);

  -- Update counters if new
  IF is_new_item THEN
    IF p_media_type = 'movie' THEN
      current_stats := jsonb_set(current_stats, '{total_movies}', ((current_stats->>'total_movies')::int + 1)::text::jsonb);
    ELSE
      current_stats := jsonb_set(current_stats, '{total_shows}', ((current_stats->>'total_shows')::int + 1)::text::jsonb);
    END IF;
  END IF;

  -- Update genres
  IF is_new_item AND p_genres IS NOT NULL THEN
    FOREACH g IN ARRAY p_genres
    LOOP
      current_stats := jsonb_set(
        current_stats,
        array['genre_counts', g],
        (COALESCE((current_stats->'genre_counts'->>g)::int, 0) + 1)::text::jsonb
      );
    END LOOP;
  END IF;

  -- Update last watched & calculate streak
  DECLARE
    previous_last_watched TIMESTAMPTZ;
    days_since_last_watch INT;
    current_streak INT;
  BEGIN
    previous_last_watched := (current_stats->>'last_watched')::timestamptz;
    current_streak := COALESCE((current_stats->>'streak_days')::int, 0);
    
    IF previous_last_watched IS NULL THEN
      -- First time watching
      current_streak := 1;
    ELSE
      -- Calculate days between last watch and today
      days_since_last_watch := EXTRACT(DAY FROM (CURRENT_DATE - DATE(previous_last_watched)));
      
      IF days_since_last_watch = 0 THEN
        -- Watched earlier today, keep streak
        current_streak := current_streak;
      ELSIF days_since_last_watch = 1 THEN
        -- Watched yesterday, increment streak
        current_streak := current_streak + 1;
      ELSE
        -- Missed a day or more, reset streak
        current_streak := 1;
      END IF;
    END IF;
    
    -- Update stats with new streak and timestamp
    current_stats := jsonb_set(current_stats, '{streak_days}', current_streak::text::jsonb);
    current_stats := jsonb_set(current_stats, '{last_watched}', to_jsonb(now()));
  END;

  -- Commit
  UPDATE public.profiles
  SET 
    watch_history = current_history,
    stats = current_stats,
    last_seen_activity = now()
  WHERE id = p_user_id;

END;
$function$
